    std::vector<int> indices_2;

    // 1. Collect indices
    for (int k = 0; k < nums.size(); ++k) {
        if (nums[k] == 1) {
            indices_1.push_back(k);
        } else if (nums[k] == 2) {
            indices_2.push_back(k);
        }
    }

    // 2. Check existence
    if (indices_1.empty() || indices_2.empty()) {
        return -1;
    }

    // 3. Calculate minimum difference
    // Initialize min_diff to a value larger than any possible difference (max N-1)
    long long min_diff = std::numeric_limits<long long>::max();

    for (int i : indices_1) {
        for (int j : indices_2) {
            // Calculate absolute difference. Indices are small enough that casting to long long before subtraction is safe.
            long long diff = std::llabs((long long)i - j);
            if (diff < min_diff) {
                min_diff = diff;
            }
        }
    }

    return min_diff;
}
